74	/* Right-justified 4-char decimal cell + space, no printf. */
75	static int format_cell(char* dst, int32_t v)
76	{
77	  char tmp[12];
78	  int t = 0, neg = v < 0;
79	  uint32_t uv = neg ? -(uint32_t) v : (uint32_t) v;
80	  if (uv == 0)
81	    tmp[t++] = '0';
82	  while (uv) {
83	    tmp[t++] = (char) ('0' + (uv % 10));
84	    uv /= 10;
85	  }
86	  if (neg)
87	    tmp[t++] = '-';
88	  int p = 0;
89	  for (int pad = 4 - t; pad > 0; pad--)
90	    dst[p++] = ' ';
91	  while (t--)
92	    dst[p++] = tmp[t];
