/* Tier-2 C-level fixture: 16x16x16 GEMM split across all three phases.
 *
 *   QEMU 1: init_matrices -- fills A and B with deterministic patterns.
 *   vsim:   matmul_kernel -- the only phase that touches sim_control via
 *           printf(); also computes C = A * B.
 *   QEMU 2: prints C row-by-row via RISC-V semihosting (SYS_WRITE0,
 *           QEMU virt has no sim_control), then re-derives the expected
 *           value of every C[i][j] and compares. Mismatch -> _exit(1).
 *
 * Cross-phase memory survival
 *   vsim's elf loader (utils/elf_loader.hpp:94) zero-fills (memsz - filesz)
 *   for every PT_LOAD on resume, which would blow away anything in .bss
 *   that QEMU 1 had written. The matrices therefore live at fixed addresses
 *   (0x80100000+) -- inside the 128 MiB shared mmap, above the ELF's last
 *   loaded byte (~0x8000d800), below the stack (0x80700000), so QEMU's
 *   -kernel load and vsim's loader both leave them untouched. The shared
 *   memory-backend-file then preserves the bytes across QEMU1 -> vsim ->
 *   QEMU2.
 */
#include "runtime/rt_c_helpers.h"

#include <stdint.h>
#include <stdio.h>

#define N 16

/* Fixed-address scratch region. Pointers (not arrays) so the compiler
 * doesn't reserve .bss for them. */
static int32_t* const A = (int32_t*) 0x80100000UL;
static int32_t* const B = (int32_t*) 0x80101000UL;
static int32_t* const C = (int32_t*) 0x80102000UL;

#define AT(M, i, j) ((M)[(i) *N + (j)])

static void init_matrices(void)
{
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      AT(A, i, j) = (int32_t) ((i + j) % 7);
      AT(B, i, j) = (int32_t) ((i * 3 + j) % 5);
    }
  }
}

static void matmul_kernel(void)
{
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      int32_t s = 0;
      for (int k = 0; k < N; k++) {
        s += AT(A, i, k) * AT(B, k, j);
      }
      AT(C, i, j) = s;
    }
  }
}

/* Independent recomputation in QEMU2 -- catches any kernel error. */
static int verify(void)
{
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      int32_t s = 0;
      for (int k = 0; k < N; k++) {
        s += AT(A, i, k) * AT(B, k, j);
      }
      if (AT(C, i, j) != s)
        return 0;
    }
  }
  return 1;
}

/* Right-justified 4-char decimal cell + space, no printf. */
static int format_cell(char* dst, int32_t v)
{
  char tmp[12];
  int t = 0, neg = v < 0;
  uint32_t uv = neg ? -(uint32_t) v : (uint32_t) v;
  if (uv == 0)
    tmp[t++] = '0';
  while (uv) {
    tmp[t++] = (char) ('0' + (uv % 10));
    uv /= 10;
  }
  if (neg)
    tmp[t++] = '-';
  int p = 0;
  for (int pad = 4 - t; pad > 0; pad--)
    dst[p++] = ' ';
  while (t--)
    dst[p++] = tmp[t];
  dst[p++] = ' ';
  return p;
}

static void semihost_print_row(const int32_t* row, int n)
{
  char line[N * 6 + 4];
  int p = 0;
  for (int i = 0; i < n; i++)
    p += format_cell(line + p, row[i]);
  line[p++] = '\n';
  line[p] = '\0';
  rt_semihost_writes(line);
}

int main(void)
{
  /* Phase 1 (QEMU 1): seed inputs. No I/O reachable. */
  init_matrices();

  rt_phase_qemu1_drain();

  /* Phase 2 (vsim): GEMM kernel + status via libgloss/sim_control. */
  setvbuf(stdout, NULL, _IONBF, 0);
  printf("rt_c_matmul: vsim running 16x16x16 GEMM\n");
  matmul_kernel();
  printf("rt_c_matmul: vsim kernel done\n");

  rt_phase_vsim_drain();

  /* Phase 3 (QEMU 2): print + verify via semihosting (no sim_control). */
  rt_semihost_writes("rt_c_matmul: C[16][16]=\n");
  for (int i = 0; i < N; i++)
    semihost_print_row(C + i * N, N);

  if (!verify()) {
    rt_semihost_writes("rt_c_matmul: FAIL\n");
    return 1;
  }
  rt_semihost_writes("rt_c_matmul: PASS\n");
  return 0;
}

/* rt_c_v_csrs.c - Round-trip fixture: V scalar CSR survival.
 *
 * Exercises vxsat, vxrm, vcsr, vtype, vl, and vstart across the
 * QEMU1 -> vsim -> QEMU2 handoff.
 *
 * Phase 1 (QEMU1): drain marker only (no V instructions; plugin PC
 *   drain constraint).
 * Phase 2 (vsim):  configure known V CSR values, then drain.
 *   - vsetvli: vl=8, vtype=e32/m1/ta/ma (0xD0)
 *   - csrw vxsat=1, vxrm=2, vstart=3 (vstart last: vsetvli resets it to 0)
 * Phase 3 (QEMU2): read V CSRs via csrr and verify each expected value.
 *   mstatus.VS is restored by ResumeDriver so no extra csrs needed.
 *   vstart is read before any V instruction so it holds the restored value.
 *
 * vcsr[0] = vxsat, vcsr[2:1] = vxrm -> expected vcsr = (2<<1)|1 = 5.
 * vtype: vsew=e32=010 at bits[5:3], vta=1 at bit6, vma=1 at bit7 -> 0xD0.
 */
#include "runtime/rt_c_helpers.h"

#include <stdint.h>

int main(void)
{
  /* Phase 1 (QEMU1): no V instructions before the drain marker. */
  rt_phase_qemu1_drain();

  /* Phase 2 (vsim): set known V CSR values.
   * crt0.S already set mstatus.VS=non-Off so vsetvli doesn't trap.
   * vstart must be written last: vsetvli resets vstart to 0. */
  asm volatile(
    "li     a0, 8\n"
    "vsetvli t0, a0, e32, m1, ta, ma\n"  /* vl=8, vtype=0xD0 */
    "li     t1, 1\n"
    "csrw   vxsat, t1\n"
    "li     t1, 2\n"
    "csrw   vxrm,  t1\n"
    "li     t1, 3\n"
    "csrw   vstart, t1\n"
    ::: "t0", "t1", "a0", "memory");

  rt_phase_vsim_drain();

  /* Phase 3 (QEMU2): verify V CSRs survived the round-trip.
   * Read vstart first, before any V instruction resets it to 0. */
  uint64_t vstart_out, vxsat_out, vxrm_out, vcsr_out, vtype_out, vl_out;
  asm volatile(
    "csrr %0, vstart\n"
    "csrr %1, vxsat\n"
    "csrr %2, vxrm\n"
    "csrr %3, vcsr\n"
    "csrr %4, vtype\n"
    "csrr %5, vl\n"
    : "=r"(vstart_out), "=r"(vxsat_out), "=r"(vxrm_out),
      "=r"(vcsr_out),   "=r"(vtype_out), "=r"(vl_out));

  int ok = 1;
  if (vl_out     != 8u)    { rt_semihost_writes("FAIL vl\n");     ok = 0; }
  if (vxsat_out  != 1u)    { rt_semihost_writes("FAIL vxsat\n");  ok = 0; }
  if (vxrm_out   != 2u)    { rt_semihost_writes("FAIL vxrm\n");   ok = 0; }
  if (vcsr_out   != 5u)    { rt_semihost_writes("FAIL vcsr\n");   ok = 0; }
  if (vtype_out  != 0xD0u) { rt_semihost_writes("FAIL vtype\n");  ok = 0; }
  if (vstart_out != 3u)    { rt_semihost_writes("FAIL vstart\n"); ok = 0; }

  if (ok)
    rt_semihost_writes("rt_c_v_csrs: PASS\n");
  else
    rt_semihost_writes("rt_c_v_csrs: FAIL\n");
  return ok ? 0 : 1;
}

