__attribute__((used, noreturn)) void _exit(int exit_status)
{
  /* In the hybrid round-trip flow, _exit is only reached in QEMU 2 (vsim
     itself terminates at the csrwi 0x7C0, 1 drain marker, well before main
     returns). QEMU 2 has -semihosting-config enable=on,target=native, so
     SYS_EXIT_EXTENDED reaches the host with the right status. The ebreak
     triple matches hybrid/test/semihost_exit.inc.

     We deliberately do NOT also poke EXIT_COMMAND_ADDR (0xE0080000) here:
     QEMU virt doesn't ignore that write -- it raises a store-access-fault
     that traps to m_trap_entry -> exception_handler, which reads Andes-only
     mdcause (CSR 0x7C9) on default -cpu rv64 and re-traps forever.

     If a fixture needs to fail-fast inside vsim, use rt_fail() in
     runtime/rt_c_helpers.h, which writes SimCommand::FAILED to sim_control
     directly and short-circuits the round-trip. */
  static volatile uint64_t semihost_block[2];
  semihost_block[0] = 0x20026; /* ADP_Stopped_ApplicationExit */
  semihost_block[1] = (uint64_t)(uint32_t) exit_status;
  register long a0 __asm__("a0") = 0x20; /* SYS_EXIT_EXTENDED */
  register long a1 __asm__("a1") = (long)(uintptr_t) semihost_block;
  __asm__ __volatile__(
    ".option push\n"
    ".option norvc\n"
    "slli x0, x0, 0x1f\n"
    "ebreak\n"
    "srai x0, x0, 0x7\n"
    ".option pop\n"
    : : "r"(a0), "r"(a1) : "memory");

  __asm__ __volatile__("1: j 1b");
  __builtin_unreachable();
}

__attribute__((used)) void* _sbrk(intptr_t increment)
{
  extern char _end[];
  static char* p = _end;
  void* base = p;
  p += increment;
  return base;
}

#ifdef __cplusplus
}
#endif

